function useActivities(limit = 10) {
  const [activities, setActivities] = reactExports.useState([]);
  const [loading, setLoading] = reactExports.useState(true);
  const [error, setError] = reactExports.useState(null);
  reactExports.useEffect(() => {
    const fetchActivities = async () => {
      try {
        setLoading(true);
        setError(null);
        const [auditActivities, importActivities] = await Promise.all([
          ActivityService.getRecentActivities(limit),
          ActivityService.getImportActivities(Math.floor(limit / 2))
        ]);
        const allActivities = [...auditActivities, ...importActivities].sort((a2, b2) => new Date(b2.timestamp).getTime() - new Date(a2.timestamp).getTime()).slice(0, limit);
        setActivities(allActivities);
      } catch (err) {
        console.error("Erro ao buscar atividades:", err);
        setError("Erro ao carregar atividades");
      } finally {
        setLoading(false);
      }
    };
    fetchActivities();
  }, [limit]);
  const refreshActivities = async () => {
    try {
      setLoading(true);
      setError(null);
      const [auditActivities, importActivities] = await Promise.all([
        ActivityService.getRecentActivities(limit),
        ActivityService.getImportActivities(Math.floor(limit / 2))
      ]);
      const allActivities = [...auditActivities, ...importActivities].sort((a2, b2) => new Date(b2.timestamp).getTime() - new Date(a2.timestamp).getTime()).slice(0, limit);
      setActivities(allActivities);
    } catch (err) {
      console.error("Erro ao atualizar atividades:", err);
      setError("Erro ao atualizar atividades");
    } finally {
      setLoading(false);
    }
  };
  return {
    activities,
    loading,
    error,
    refreshActivities
  };
}
